// ══════════════════════════════════════════════════════════════════════
// ── VERCEL-READY EXPORT BUNDLER ──
// Takes project files produced by the brief-builder pipeline (which assume
// React hooks are global, no JSX import, etc. — i.e. preview-runtime-ready)
// and wraps them in a standalone Vite + React + Tailwind project that can be
// deployed to Vercel/Netlify/any static host as-is.
// ══════════════════════════════════════════════════════════════════════

const REACT_HOOKS = [
  'useState', 'useEffect', 'useRef', 'useCallback', 'useMemo', 'useContext',
  'useReducer', 'useLayoutEffect', 'useId', 'useTransition', 'useDeferredValue',
  'createContext', 'forwardRef', 'memo', 'lazy', 'Suspense', 'Fragment',
]

/**
 * Prepend a React import to a JSX/JS file so it works in a real bundler.
 * Generated files rely on React + hooks being global (preview-runtime
 * behavior). We auto-inject `import React, { ...hooks } from 'react'` at the
 * top of every .jsx/.js file that doesn't already import React.
 */
function injectReactImport(content) {
  if (!content || typeof content !== 'string') return content
  // Already imports React — leave as-is
  if (/^\s*import\s+React\s+from\s+['"]react['"]/m.test(content)) return content
  if (/^\s*import\s+\*\s+as\s+React\s+from\s+['"]react['"]/m.test(content)) return content

  // Find which hooks are actually referenced so we only import what's used
  const used = REACT_HOOKS.filter((h) => new RegExp('\\b' + h + '\\b').test(content))
  const hooksImport = used.length > 0
    ? `import React, { ${used.join(', ')} } from 'react'\n`
    : `import React from 'react'\n`
  return hooksImport + content
}

/**
 * Build the package.json for the exported project.
 * @param {Object} project — the Auroraly project record
 * @param {Object} opts — { useSupabase: boolean, useStripe: boolean, useReactRouter: boolean }
 */
function buildPackageJson(project, opts = {}) {
  const projectName = (project?.name || 'emanator-app')
    .toLowerCase().replace(/[^a-z0-9-]/g, '-').replace(/-+/g, '-').slice(0, 60) || 'emanator-app'

  const deps = {
    'react': '^18.3.1',
    'react-dom': '^18.3.1',
  }
  if (opts.useReactRouter) deps['react-router-dom'] = '^6.26.2'
  if (opts.useSupabase) deps['@supabase/supabase-js'] = '^2.45.0'
  if (opts.useStripe) deps['@stripe/stripe-js'] = '^4.5.0'

  return JSON.stringify({
    name: projectName,
    version: '0.1.0',
    private: true,
    type: 'module',
    scripts: {
      dev: 'vite',
      build: 'vite build',
      preview: 'vite preview',
    },
    dependencies: deps,
    devDependencies: {
      '@vitejs/plugin-react': '^4.3.1',
      autoprefixer: '^10.4.20',
      postcss: '^8.4.47',
      tailwindcss: '^3.4.13',
      vite: '^5.4.8',
    },
  }, null, 2)
}

const VITE_CONFIG = `import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

// https://vitejs.dev/config/
export default defineConfig({
  plugins: [react()],
})
`

const INDEX_HTML = (brandName = 'App') => `<!doctype html>
<html lang="en" class="dark">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>${brandName.replace(/</g, '&lt;')}</title>
  </head>
  <body class="bg-black text-white">
    <div id="root"></div>
    <script type="module" src="/src/main.jsx"></script>
  </body>
</html>
`

const MAIN_JSX = `import React from 'react'
import { createRoot } from 'react-dom/client'
import './index.css'
import App from './App.jsx'

createRoot(document.getElementById('root')).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
)
`

const INDEX_CSS = `@tailwind base;
@tailwind components;
@tailwind utilities;

html, body, #root { min-height: 100%; }
`

const TAILWIND_CONFIG = `/** @type {import('tailwindcss').Config} */
export default {
  content: ['./index.html', './src/**/*.{js,jsx,ts,tsx}'],
  theme: { extend: {} },
  plugins: [],
  darkMode: 'class',
}
`

const POSTCSS_CONFIG = `export default {
  plugins: {
    tailwindcss: {},
    autoprefixer: {},
  },
}
`

const README = (project, opts) => `# ${project?.name || 'Auroraly App'}

Generated by Auroraly. Vercel/Netlify-ready.

## Run locally

\`\`\`bash
npm install
npm run dev
\`\`\`

## Deploy

### Vercel

1. Push this folder to a GitHub repo
2. Import the repo at [vercel.com/new](https://vercel.com/new)
3. Vercel auto-detects Vite — click Deploy

### Netlify

Set build command: \`npm run build\`, publish directory: \`dist\`.

${opts?.useSupabase ? `## Supabase

This app is wired to your Supabase project. Create a \`.env.local\` with:

\`\`\`
VITE_SUPABASE_URL=your-project-url
VITE_SUPABASE_ANON_KEY=your-anon-key
\`\`\`

On Vercel, add these as environment variables in the project dashboard.

` : ''}${opts?.useStripe ? `## Stripe

This app uses Stripe Checkout. Add to \`.env.local\`:

\`\`\`
VITE_STRIPE_PUBLISHABLE_KEY=pk_live_or_test_…
\`\`\`

You also need a server-side endpoint at \`/api/stripe/checkout\` that creates a Checkout session and returns \`{ id, url }\`. Two quick paths:

- **Vercel**: add \`api/stripe/checkout.js\` using \`stripe\` npm package (server-only — never expose your secret key).
- **Supabase Edge Function**: deploy a function that handles the same contract.

Required env on the server side:
\`\`\`
STRIPE_SECRET_KEY=sk_live_or_test_…
\`\`\`

The pricing page falls back to the signup route when Stripe isn't configured — preview keeps working.

` : ''}## Notes

- Generated files assume React + hooks are global; \`main.jsx\` + per-file imports handle that.
- Tailwind is configured via \`tailwind.config.js\`.
- Original Auroraly project ID: \`${project?.id || 'unknown'}\`
`

const GITIGNORE = `node_modules
dist
.env
.env.local
.DS_Store
`

/**
 * Produce a map { path: content } of all files for a standalone Vite project.
 * Assumes `files` is the raw list of generated project files (path + content)
 * from db.projectFiles.findByProjectId.
 *
 * @param {{id:string,name:string,settings?:any}} project
 * @param {{path:string,content:string}[]} files
 * @returns {{[path:string]: string}}
 */
export function buildVercelReadyFileMap(project, files) {
  const settings = project?.settings || {}
  const supa = settings.supabase || {}
  const stripe = settings.stripe || {}
  const useSupabase = !!(supa.url && supa.anonKey)
  const useStripe = !!stripe.publishableKey

  // Detect if any generated file imports 'react-router-dom' so we include it
  // as a dep. Most apps don't use it, but a few do via recipes.
  const useReactRouter = (files || []).some((f) => /['"]react-router-dom['"]/.test(f?.content || ''))

  const out = {}

  // Scaffold files
  out['package.json'] = buildPackageJson(project, { useSupabase, useStripe, useReactRouter })
  out['vite.config.js'] = VITE_CONFIG
  out['index.html'] = INDEX_HTML(project?.name || 'App')
  out['src/main.jsx'] = MAIN_JSX
  out['src/index.css'] = INDEX_CSS
  out['tailwind.config.js'] = TAILWIND_CONFIG
  out['postcss.config.js'] = POSTCSS_CONFIG
  out['README.md'] = README(project, { useSupabase, useStripe })
  out['.gitignore'] = GITIGNORE

  // If user configured Supabase/Stripe, emit a .env.local template (gitignored)
  if (useSupabase || useStripe) {
    const envLines = []
    if (useSupabase) {
      envLines.push(`VITE_SUPABASE_URL=${supa.url || ''}`)
      envLines.push(`VITE_SUPABASE_ANON_KEY=${supa.anonKey || ''}`)
    }
    if (useStripe) {
      envLines.push(`VITE_STRIPE_PUBLISHABLE_KEY=${stripe.publishableKey || ''}`)
    }
    out['.env.local.example'] = envLines.join('\n') + '\n'
  }

  // Emit all generated files under src/, injecting React imports so they
  // work outside the preview runtime.
  for (const f of files || []) {
    if (!f?.path) continue
    const path = f.path.replace(/^\/+/, '')
    // Skip anything already under src/ — keep it at src/<path>
    const outPath = path.startsWith('src/') ? path : 'src/' + path
    const isJsx = /\.(jsx|js|tsx|ts)$/.test(path)

    // When Supabase is wired, replace the preview-safe supabaseClient file
    // with real Vite + @supabase/supabase-js wiring that reads from env vars.
    if (useSupabase && /components\/supabaseClient\.(jsx|js)$/.test(path)) {
      out[outPath] = `import { createClient } from '@supabase/supabase-js'

const url = import.meta.env.VITE_SUPABASE_URL
const key = import.meta.env.VITE_SUPABASE_ANON_KEY

export const supabase = (url && key) ? createClient(url, key) : null
export const hasSupabase = !!(url && key)
export default supabase
`
      continue
    }

    // When Stripe is wired, replace the preview-safe stripeClient with
    // real @stripe/stripe-js loader using env var.
    if (useStripe && /components\/stripeClient\.(jsx|js)$/.test(path)) {
      out[outPath] = `import { loadStripe } from '@stripe/stripe-js'

const key = import.meta.env.VITE_STRIPE_PUBLISHABLE_KEY
const stripePromise = key ? loadStripe(key) : null

export const getStripe = () => stripePromise
export const hasStripe = !!key
export default getStripe
`
      continue
    }

    out[outPath] = isJsx ? injectReactImport(f.content || '') : (f.content || '')
  }

  // If there's no App.jsx at the top level of src/, and there IS one at src/app/
  // or similar, create a re-export so src/main.jsx can `import App from './App.jsx'`
  if (!out['src/App.jsx'] && !out['src/App.js']) {
    // Find most likely App file
    const appCandidates = Object.keys(out).filter((p) =>
      /\/(App)\.(jsx|js|tsx)$/i.test(p) || /src\/app\/page\.(jsx|js|tsx)$/i.test(p)
    )
    if (appCandidates.length > 0) {
      const rel = './' + appCandidates[0].replace(/^src\//, '').replace(/\.(jsx|js|tsx)$/, '')
      out['src/App.jsx'] = `import App from '${rel}'\nexport default App\n`
    } else {
      // Graceful fallback placeholder so the build doesn't break
      out['src/App.jsx'] = `import React from 'react'
export default function App() {
  return (
    <div className="min-h-screen flex items-center justify-center p-8 text-center">
      <div>
        <h1 className="text-3xl font-bold mb-2">Export succeeded</h1>
        <p className="text-white/60">No App.jsx was found. Add your root component at <code>src/App.jsx</code>.</p>
      </div>
    </div>
  )
}
`
    }
  }

  return out
}
